49	@OptIn(FlowPreview::class)
50	@HiltViewModel
51	class ComposeViewModel @Inject constructor(
52	    private val repository: HackersPubRepository,
53	    @ApplicationContext private val context: Context
54	) : ViewModel() {
55	
56	    private val _uiState = MutableStateFlow(ComposeUiState())
57	    val uiState: StateFlow<ComposeUiState> = _uiState.asStateFlow()
58	
59	    private var viewerHandle: String? = null
60	
61	    // Regex to detect @mention at cursor position
62	    // Matches: @handle or @user@domain patterns that are incomplete
63	    private val mentionRegex = Regex("""@([^\s@]+(?:@[^\s@]*)?)$""")
64	
65	    private val mentionQueryFlow = MutableSharedFlow<String>(replay = 0)
66	
67	    init {
68	        viewModelScope.launch {
69	            repository.getViewer().onSuccess { viewer ->
70	                viewerHandle = viewer?.handle
71	            }
72	        }
73	
74	        // Setup debounced mention search
75	        viewModelScope.launch {
76	            mentionQueryFlow
77	                .debounce(300L)
78	                .collectLatest { query ->
79	                    if (query.isNotEmpty()) {
80	                        searchMentions(query)
81	                    }
82	                }
83	        }
84	    }
85	
86	    private suspend fun searchMentions(query: String) {
87	        _uiState.update { it.copy(isLoadingMentions = true) }
88	
89	        repository.searchActorsByHandle(query, limit = 10)
90	            .onSuccess { actors ->
91	                _uiState.update {
92	                    it.copy(
93	                        mentionSuggestions = actors,
94	                        isLoadingMentions = false
95	                    )
96	                }
97	            }
98	            .onFailure {
99	                _uiState.update {
100	                    it.copy(
101	                        mentionSuggestions = emptyList(),
102	                        isLoadingMentions = false
103	                    )
104	                }
105	            }
106	    }
107	
108	    private fun detectMentionTrigger(content: String, cursorPosition: Int) {
109	        // Get text before cursor
110	        val textBeforeCursor = content.take(cursorPosition)
111	
112	        // Find mention pattern at cursor position
113	        val match = mentionRegex.find(textBeforeCursor)
114	
115	        if (match != null) {
116	            val mentionQuery = match.groupValues[1]
117	            val mentionStartIndex = match.range.first
118	
119	            _uiState.update {
120	                it.copy(
121	                    mentionQuery = mentionQuery,
122	                    mentionStartIndex = mentionStartIndex
123	                )
124	            }
125	
126	            // Trigger debounced search
127	            viewModelScope.launch {
128	                mentionQueryFlow.emit(mentionQuery)
129	            }
130	        } else {
131	            // Clear mention state
132	            clearMentionState()
133	        }
134	    }
135	
136	    private fun clearMentionState() {
137	        _uiState.update {
138	            it.copy(
139	                mentionQuery = null,
140	                mentionStartIndex = -1,
141	                mentionSuggestions = emptyList(),
142	                isLoadingMentions = false
143	            )
144	        }
145	    }
146	
147	    fun selectMention(actor: Actor): Pair<String, Int> {
148	        val state = _uiState.value
149	        val content = state.content
150	        val startIndex = state.mentionStartIndex
151	
152	        if (startIndex >= 0) {
153	            // Replace @partial with @full_handle
154	            val beforeMention = content.take(startIndex)
155	            val textAfterMentionStart = content.drop(startIndex)
156	
157	            // Find where the partial mention ends (next space, newline, or end of string)
158	            val mentionEndOffset = textAfterMentionStart.indexOfFirst { it == ' ' || it == '\n' }
159	            val afterMention = if (mentionEndOffset >= 0) {
160	                textAfterMentionStart.drop(mentionEndOffset)
161	            } else {
162	                " " // Add space after mention if at end
163	            }
164	
165	            val normalizedHandle = actor.handle.removePrefix("@")
166	            val insertedHandle = "@$normalizedHandle "
167	            val newContent = "$beforeMention$insertedHandle${afterMention.trimStart()}"
168	            val newCursorPosition = beforeMention.length + insertedHandle.length
169	
170	            _uiState.update {
171	                it.copy(
172	                    content = newContent,
173	                    cursorPosition = newCursorPosition,
174	                    mentionQuery = null,
175	                    mentionStartIndex = -1,
176	                    mentionSuggestions = emptyList(),
177	                    isLoadingMentions = false
178	                )
179	            }
180	
181	            return Pair(newContent, newCursorPosition)
182	        }
183	
184	        return Pair(content, state.cursorPosition)
185	    }
186	
187	    fun dismissMentionSuggestions() {
188	        clearMentionState()
189	    }
