209	    fun setReplyTarget(postId: String) {
210	        _uiState.update { it.copy(replyToId = postId, isLoadingReplyTarget = true) }
211	        viewModelScope.launch {
212	            repository.getPostDetail(postId)
213	                .onSuccess { result ->
214	                    val post = result.post
215	                    val mentionPrefix = buildMentionPrefix(post)
216	                    _uiState.update {
217	                        it.copy(
218	                            replyTargetPost = post,
219	                            isLoadingReplyTarget = false,
220	                            content = if (it.content.isBlank()) mentionPrefix else it.content,
221	                            cursorPosition = if (it.content.isBlank()) mentionPrefix.length else it.cursorPosition
222	                        )
223	                    }
224	                }
225	                .onFailure {
226	                    _uiState.update { it.copy(isLoadingReplyTarget = false) }
227	                }
228	        }
229	    }
230	
231	    private fun buildMentionPrefix(post: Post): String {
232	        val mentions = mutableSetOf<String>()
233	
234	        // Add the post author (normalize by removing leading @)
235	        mentions.add(post.actor.handle.removePrefix("@"))
236	
237	        // Add existing mentions from the post (normalize)
238	        mentions.addAll(post.mentions.map { it.removePrefix("@") })
239	
240	        // Remove viewer's own handle if present (normalize for comparison)
241	        viewerHandle?.let { mentions.remove(it.removePrefix("@")) }
